export type LogoLockupProps = {
  color?: string;
  size?: SolmLogoSize;
  className?: string;
};

export function LogoLockup({ color = '#ffffff', size = 'lg', className }: LogoLockupProps) {
  const markPx = sizeConfig[size].mark;
  const scale = markPx / circleDiameterSvg;
  const width = lockupViewBox.w * scale;
  const height = lockupViewBox.h * scale;

  return (
    <svg
      width={width}
      height={height}
      viewBox={`${lockupViewBox.x} ${lockupViewBox.y} ${lockupViewBox.w} ${lockupViewBox.h}`}
      fill="none"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      aria-label="solm"
    >
      <path d={outerCirclePath} stroke={color} strokeWidth={3} />
      <path d={innerCirclePath} fill={color} />
      <path d={wordmarkPath} fill={color} />
    </svg>
  );
}

export function LoginLogoHero({ size = 'lg' }: { size?: SolmLogoSize }) {
  return (
    <>
      <LogoLockup color="#ffffff" size={size} />
      <p
        style={{
          marginTop: '6px',
          paddingLeft: '68px',
          fontSize: '11px',
          fontWeight: 400,
          color: '#2e2e2e',
          letterSpacing: '0.3em',
          textTransform: 'uppercase',
        }}
      >
        The one thing.
      </p>
    </>
  );
}
